import React from "react"
import { Helmet } from "react-helmet"
import Footer from "../components/footer"
import { AboutMe } from "./landing/aboutMe"
import SkillCards from "./landing/skillCards"

export default class Landing extends React.Component {

    render() {
        return (
            <div className="landing_main container">
                <Helmet title={"portfolio"} meta={[
                    { name: "description", content: "A list of projects built by Radu" },
                    { name: "keywords", content: "projects, portfolio, Javascript, React" },
                ]}>
                    <html lang="en" />
                </Helmet>
                <AboutMe />
                <br />
                <SkillCards />
                <Footer />
            </div>
        )
    }
}
